import React, { useEffect, useState } from 'react';
import './CryptoBackground.css';

// Importando todos os logos
import binanceLogo from '../../assets/crypto_logos/binance.svg';
import bitcoinLogo from '../../assets/crypto_logos/bitcoin.svg';
import cardanoLogo from '../../assets/crypto_logos/cardano.svg';
import chainlinkLogo from '../../assets/crypto_logos/chainlink.svg';
import dogecoinLogo from '../../assets/crypto_logos/dogecoin.svg';
import ethereumLogo from '../../assets/crypto_logos/ethereum.svg';
import litecoinLogo from '../../assets/crypto_logos/litecoin.svg';
import polkadotLogo from '../../assets/crypto_logos/polkadot.svg';
import polygonLogo from '../../assets/crypto_logos/polygon.svg';
import rippleLogo from '../../assets/crypto_logos/ripple.svg';
import solanaLogo from '../../assets/crypto_logos/solana.svg';

const logos = [
  binanceLogo,
  bitcoinLogo,
  cardanoLogo,
  chainlinkLogo,
  dogecoinLogo,
  ethereumLogo,
  litecoinLogo,
  polkadotLogo,
  polygonLogo,
  rippleLogo,
  solanaLogo,
];

const CryptoBackground = () => {
  const [symbols, setSymbols] = useState([]);

  useEffect(() => {
    // Função para criar um novo símbolo
    const createSymbol = () => {
      const size = Math.random() * (35 - 20) + 20; // Tamanho entre 20px e 35px
      const duration = Math.random() * (30 - 20) + 20; // Duração entre 20s e 30s
      
      // Distribuir os símbolos em 5 colunas
      const columns = [10, 30, 50, 70, 90];
      const columnVariation = Math.random() * 10 - 5; // Variação de ±5% na posição
      const left = columns[Math.floor(Math.random() * columns.length)] + columnVariation;
      
      return {
        id: Math.random(),
        logo: logos[Math.floor(Math.random() * logos.length)],
        left: left,
        size: size,
        duration: duration,
        delay: Math.random() * -15, // Delay negativo para começar em posições diferentes
        opacity: Math.random() * (0.5 - 0.2) + 0.2, // Opacidade entre 0.2 e 0.5
      };
    };

    // Criar símbolos iniciais
    const initialSymbols = Array.from({ length: 25 }, createSymbol);
    setSymbols(initialSymbols);

    // Adicionar novos símbolos periodicamente
    const interval = setInterval(() => {
      setSymbols(prev => [...prev.slice(-24), createSymbol()]);
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="crypto-background">
      {symbols.map(symbol => (
        <img
          key={symbol.id}
          src={symbol.logo}
          alt="crypto"
          className="floating-symbol"
          style={{
            left: `${symbol.left}%`,
            width: `${symbol.size}px`,
            height: `${symbol.size}px`,
            animationDuration: `${symbol.duration}s`,
            animationDelay: `${symbol.delay}s`,
            opacity: symbol.opacity,
          }}
        />
      ))}
    </div>
  );
};

export default CryptoBackground;
